package pe.org.camaracomercioica.protestos.service;
import lombok.RequiredArgsConstructor; import org.springframework.data.domain.*; import org.springframework.stereotype.Service; import org.springframework.transaction.annotation.Transactional; import pe.org.camaracomercioica.protestos.dto.*; import pe.org.camaracomercioica.protestos.exception.*; import pe.org.camaracomercioica.protestos.model.*; import pe.org.camaracomercioica.protestos.repository.*; import pe.org.camaracomercioica.protestos.util.SolicitudStatePolicy; import java.time.Instant; import java.util.UUID;
@Service @RequiredArgsConstructor public class SolicitudService { private final SolicitudRepository solicitudes; private final UsuarioRepository usuarios; private final EntidadFinancieraRepository entidades; private final AnalistaRepository analistas; private final AuditoriaService auditoria;
 @Transactional public SolicitudResponse crear(SolicitudRequest r,String email){var u=usuarios.findByEmailIgnoreCase(email).orElseThrow(()->new ResourceNotFoundException("Usuario no encontrado"));var e=entidades.findById(r.entidadId()).orElseThrow(()->new ResourceNotFoundException("Entidad no encontrada"));if("ENTIDAD".equals(u.getRol().getNombre())&&(u.getEntidad()==null||!u.getEntidad().getId().equals(e.getId())))throw new org.springframework.security.access.AccessDeniedException("Solo puede registrar solicitudes para su propia entidad");var s=new Solicitud();s.setCodigo("SOL-"+UUID.randomUUID().toString().substring(0,8).toUpperCase());s.setSolicitante(u);s.setEntidad(e);s.setMotivo(r.motivo().trim());s=solicitudes.save(s);auditoria.registrar(email,"CREAR","SOLICITUD",s.getId(),s.getCodigo());return map(s);}
 @Transactional(readOnly=true) public Page<SolicitudResponse> listar(EstadoSolicitud estado,Long entidadId,Pageable p){return solicitudes.filtrar(estado,entidadId,p).map(this::map);} @Transactional(readOnly=true) public Page<SolicitudResponse> mias(String email,Pageable p){return solicitudes.findBySolicitanteEmailIgnoreCase(email,p).map(this::map);}
 @Transactional public SolicitudResponse cambiarEstado(Long id,CambioEstadoRequest r,String actor){var s=solicitudes.findById(id).orElseThrow(()->new ResourceNotFoundException("Solicitud no encontrada"));if(!SolicitudStatePolicy.canTransition(s.getEstado(),r.estado()))throw new BadRequestException("Transición de estado no permitida");s.setEstado(r.estado());s.setObservacion(r.observacion());if(r.analistaId()!=null)s.setAnalista(analistas.findById(r.analistaId()).orElseThrow(()->new ResourceNotFoundException("Analista no encontrado")));s.setActualizadoEn(Instant.now());s=solicitudes.save(s);auditoria.registrar(actor,"CAMBIAR_ESTADO","SOLICITUD",id,r.estado().name());return map(s);}
 private SolicitudResponse map(Solicitud s){return new SolicitudResponse(s.getId(),s.getCodigo(),s.getSolicitante().getNombreCompleto(),s.getEntidad().getRazonSocial(),s.getAnalista()==null?null:s.getAnalista().getUsuario().getNombreCompleto(),s.getEstado(),s.getMotivo(),s.getObservacion(),s.getCreadoEn(),s.getActualizadoEn());}}
